int counter = 0;

int btnAddPin = 9;
int btnSubPin = 10;
int potPin = 14;

int lastAddState = HIGH;
int lastSubState = HIGH;

int segmentPins[7] = {2, 3, 4, 5, 6, 7, 8};

void setup() {
  pinMode(btnAddPin, INPUT_PULLUP);
  pinMode(btnSubPin, INPUT_PULLUP);
  pinMode(potPin, INPUT);
  for (int i = 0; i < 7; i++) {
    pinMode(segmentPins[i], OUTPUT);
  }
  displayDigit(0);
}

void loop() {
  int addState = digitalRead(btnAddPin);
  int subState = digitalRead(btnSubPin);

  // Read potentiometer and map to 0-9
  int potValue = analogRead(potPin);
  int potCounter = map(potValue, 0, 1023, 0, 9);

  // Button: increment
  if (addState == LOW && lastAddState == HIGH) {
    if (counter < 9) {
      counter++;
      displayDigit(counter);
    }
    delay(20);
  }

  // Button: decrement
  if (subState == LOW && lastSubState == HIGH) {
    if (counter > 0) {
      counter--;
      displayDigit(counter);
    }
    delay(20);
  }

  // Potentiometer: directly set display
  if (potCounter != counter) {
    counter = potCounter;
    displayDigit(counter);
  }

  lastAddState = addState;
  lastSubState = subState;
  delay(10);
}

